function requireRoutes(){if(!window.TavallRoutes)throw new Error("Routes are not initialized. Ensure constants/routes is rendered.");return window.TavallRoutes}function sanitizePath(e){return e.startsWith("#")?e.slice(1):e}function resolvePath(e,t){let a=sanitizePath(e);return Object.entries(t).forEach((([e,t])=>{a=a.replace(`{${e}}`,encodeURIComponent(String(t)))})),a}const routes=requireRoutes();export const ApiRoutes={auth:{magicRequest:sanitizePath(routes.api.auth.magicRequest),magicVerify:sanitizePath(routes.api.auth.magicVerify)},intake:{state:e=>resolvePath(routes.api.intake.state,{sessionKey:e}),cartItems:e=>resolvePath(routes.api.intake.cartItems,{sessionKey:e}),cartItem:(e,t)=>resolvePath(routes.api.intake.cartItem,{sessionKey:e,index:t}),addons:e=>resolvePath(routes.api.intake.addons,{sessionKey:e}),evaluate:sanitizePath(routes.api.intake.evaluate),spec:sanitizePath(routes.api.intake.spec),checkout:sanitizePath(routes.api.intake.checkout)},marketplace:{hireDirect:sanitizePath(routes.api.marketplace.hireDirect),portfolios:sanitizePath(routes.api.marketplace.portfolios),freelancerJobs:sanitizePath(routes.api.marketplace.freelancerJobs),clientDashboard:sanitizePath(routes.api.marketplace.clientDashboard),freelancerDashboard:sanitizePath(routes.api.marketplace.freelancerDashboard),adminStats:sanitizePath(routes.api.marketplace.adminStats)},freelancer:{portfolio:e=>resolvePath(routes.api.freelancer.portfolio,{userId:e}),workspace:sanitizePath(routes.api.freelancer.workspace),workspaceActivate:sanitizePath(routes.api.freelancer.workspaceActivate)}};export const PageRoutes={home:sanitizePath(routes.pages.home),hireDirect:sanitizePath(routes.pages.hireDirect),portfolios:sanitizePath(routes.pages.portfolios),freelancer:sanitizePath(routes.pages.freelancer),clientDashboard:sanitizePath(routes.pages.clientDashboard),freelancerDashboard:sanitizePath(routes.pages.freelancerDashboard),freelancerPortfolio:e=>resolvePath(routes.pages.freelancerPortfolio,{userId:e})};